const files = $.steps.listFiles.response.files || [];
const cvFiles = files.filter(f => {
  const name = (f.name || '').toLowerCase();
  return name.includes('.pdf') || name.includes('.doc') || name.includes('.txt') || name.includes('cv') || name.includes('resume');
});
let fileList = '';
cvFiles.forEach((f, i) => {
  fileList += (i+1) + '. Name: ' + f.name + '\n';
  fileList += '   ID: ' + f.id + '\n';
  fileList += '   Type: ' + (f.mimeType || 'unknown') + '\n';
  fileList += '   Link: ' + (f.webViewLink || '') + '\n';
  fileList += '   Created: ' + (f.createdTime || '') + '\n\n';
});
return { fileList, fileCount: cvFiles.length, allFileCount: files.length, fileNames: cvFiles.map(f => f.name) };

const prompt = `You are an expert HR recruiter and CV analyst. Analyze the following candidate CVs/resumes for the position described below.

JOB TITLE: ${$.input.jobTitle}
JOB REQUIREMENTS: ${$.input.jobRequirements}

FILES FOUND IN CV FOLDER (${$.steps.parseFiles.output.fileCount} CVs):
${$.steps.parseFiles.output.fileList}

INSTRUCTIONS:
- Based on the file names and available metadata, analyze and rank the candidates
- Score each candidate 1-100 based on likely fit with the job requirements
- Extract candidate name from filename where possible
- Provide a brief assessment for each candidate
- Rank from best to worst fit

Return ONLY valid JSON:
{
  "candidates": [
    {
      "rank": 1,
      "name": "<extracted name>",
      "fileName": "<original file name>",
      "score": 85,
      "assessment": "<brief assessment>",
      "strengths": ["<strength1>"],
      "concerns": ["<concern1>"],
      "recommendation": "Shortlist|Consider|Reject"
    }
  ],
  "totalCandidates": 0,
  "topPick": "<name of best candidate>",
  "summary": "<overall summary of candidate pool>"
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { candidates: [], totalCandidates: 0, topPick: '', summary: raw }; }

const ai = $.steps.parseAI.output;
const candidates = ai.candidates || [];
const date = new Date().toISOString().split('T')[0];
const sheetData = candidates.map(c => ({
  'Rank': c.rank || '',
  'Candidate Name': c.name || '',
  'File Name': c.fileName || '',
  'Score': c.score || '',
  'Recommendation': c.recommendation || '',
  'Assessment': (c.assessment || '').slice(0, 200),
  'Strengths': (c.strengths || []).join('; ').slice(0, 200),
  'Concerns': (c.concerns || []).join('; ').slice(0, 200),
  'Job Title': $.input.jobTitle,
  'Date': date
}));
return { sheetData, candidateCount: candidates.length, date, topPick: ai.topPick || '' };
